    fammap={"temporal_order_accuracy":"TEMPORAL_ORDER_RECOVERY","multi_stream_routing_accuracy":"MULTI_STREAM_ROUTING","cross_codec_event_alignment_accuracy":"CROSS_CODEC_EVENT_ALIGNMENT","entity_binding_accuracy":"ENTITY_BINDING","shared_state_reconstruction_accuracy":"SHARED_STATE_RECONSTRUCTION","missing_modality_robustness_accuracy":"MISSING_MODALITY_ROBUSTNESS","contradictory_modality_repair_accuracy":"CONTRADICTORY_MODALITY_REPAIR","noisy_stream_repair_accuracy":"NOISY_STREAM_REPAIR","delayed_evidence_binding_accuracy":"DELAYED_EVIDENCE_BINDING","causal_constraint_repair_accuracy":"CAUSAL_CONSTRAINT_REPAIR","query_over_binary_memory_accuracy":"QUERY_OVER_BINARY_MEMORY","codec_heldout_transfer_accuracy":"CODEC_HELDOUT_TRANSFER","multi_pocket_grounding_convergence_accuracy":"MULTI_POCKET_GROUNDING_CONVERGENCE","adversarial_false_alignment_rejection_accuracy":"ADVERSARIAL_FALSE_ALIGNMENT","abstain_on_ungrounded_query_accuracy":"ABSTAIN_ON_UNGROUNDED_QUERY","cross_modal_necessity_accuracy":"CROSS_MODAL_NECESSITY","occlusion_recovery_accuracy":"OCCLUSION_RECOVERY","split_merge_identity_accuracy":"SPLIT_MERGE_IDENTITY"}
    out={"episode_count":float(len(ss)),"frame_boundary_accuracy":mb('frame_boundary_correct'),"packet_sync_accuracy":mb('packet_sync_correct'),"hallucinated_state_rate":mb('hallucinated_state'),"wrong_binding_rate":mb('wrong_binding'),"wrong_stream_route_rate":mb('wrong_stream_route'),"overconfident_wrong_state_rate":mb('overconfident_wrong_state'),"false_alignment_rate":mb('false_alignment_error'),"trace_validity":mb('trace_valid'),"renderer_faithfulness":mb('renderer_faithful'),"deterministic_replay_match_rate":mb('deterministic_replay_match'),"cost_per_episode":mean([r['cost_per_episode'] for r in ss])}
    for k,f in fammap.items(): out[k]=mb('exact_answer',[r for r in ss if r['family']==f])
